import { NgModule } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule, Routes } from '@angular/router';

import { BROComponent } from './bro/bro.component';
import { PLCComponent } from './plc/plc.component';
import { SCNComponent } from './scn/scn.component';



const routes: Routes = [{
  path: 'bro',
  component: BROComponent
}, {
  path: 'plc',
  component: PLCComponent
}, {
  path: 'scn',
  component: SCNComponent
}];

@NgModule({
  declarations: [],
  imports: [
    CommonModule,
    RouterModule.forChild(routes)
  ],
  exports: [RouterModule]
})
export class IOSRoutingModule { }
